# OEIS sequence: A008949

def Trow(n: int) -> list[int]:
    row = [0] * (n + 1)
    s, c = 0, 1
    for k in range(n + 1):
        s += c
        row[k] = s
        if k < n: c = c * (n - k) // (k + 1)
    return row
for n in range(9): print(Trow(n))  # _Peter Luschny_, May 18 2026

